    public Object parseLedgerEntry(Object item, Object... optionalArgs)
    {
        //
        //     {
        //         "eid": "2510b3e2bc1c87f584500a18084f35ed",
        //         "created_at": "2022-06-08T12:21:42+0000",
        //         "balance_updates": [{
        //             "amount": "0.00080000",
        //             "currency": "btc"
        //         }],
        //         "operation": "funding",
        //         "details": {
        //             "network": "btc",
        //             "method": "btc",
        //             "method_name": "Bitcoin",
        //             "asset": "btc",
        //             "protocol": "btc",
        //             "integration": "bitgo-v2",
        //             "fid": "6112c6369100d6ecceb7f54f17cf0511"
        //         }
        //     }
        //
        //  trade
        //     {
        //         "eid": "8976c6053f078f704f037d82a813678a",
        //         "created_at": "2022-06-08T17:01:48+0000",
        //         "balance_updates": [{
        //                 "amount": "59.21320500",
        //                 "currency": "mxn"
        //             },
        //             {
        //                 "amount": "-0.00010000",
        //                 "currency": "btc"
        //             }
        //         ],
        //         "operation": "trade",
        //         "details": {
        //             "tid": "72145428",
        //             "oid": "JO5TZmMZjzjlZDyT"
        //         }
        //     }
        //
        //  fee
        //     {
        //         "eid": "cbbb3c8d4e41723d25d2850dcb7c3c74",
        //         "created_at": "2022-06-08T17:01:48+0000",
        //         "balance_updates": [{
        //             "amount": "-0.38488583",
        //             "currency": "mxn"
        //         }],
        //         "operation": "fee",
        //         "details": {
        //             "tid": "72145428",
        //             "oid": "JO5TZmMZjzjlZDyT"
        //         }
        //     }
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object operation = this.safeString(item, "operation");
        Object type = this.parseLedgerEntryType(operation);
        Object balanceUpdates = this.safeValue(item, "balance_updates", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object firstBalance = this.safeValue(balanceUpdates, 0, new java.util.HashMap<String, Object>() {{}});
        Object direction = null;
        Object fee = null;
        Object amount = this.safeString(firstBalance, "amount");
        Object currencyId = this.safeString(firstBalance, "currency");
        Object code = this.safeCurrencyCode(currencyId, currency);
        currency = this.safeCurrency(currencyId, currency);
        Object details = this.safeValue(item, "details", new java.util.HashMap<String, Object>() {{}});
        Object referenceId = this.safeString2(details, "fid", "wid");
        if (Helpers.isTrue(Helpers.isEqual(referenceId, null)))
        {
            referenceId = this.safeString(details, "tid");
        }
        if (Helpers.isTrue(Helpers.isEqual(operation, "funding")))
        {
            direction = "in";
        } else if (Helpers.isTrue(Helpers.isEqual(operation, "withdrawal")))
        {
            direction = "out";
        } else if (Helpers.isTrue(Helpers.isEqual(operation, "trade")))
        {
            direction = null;
        } else if (Helpers.isTrue(Helpers.isEqual(operation, "fee")))
        {
            direction = "out";
            Object cost = Precise.stringAbs(amount);
            final Object finalCurrency = currency;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", cost );
                put( "currency", finalCurrency );
            }};
        }
        Object timestamp = this.parse8601(this.safeString(item, "created_at"));
        final Object finalDirection = direction;
        final Object finalReferenceId = referenceId;
        final Object finalFee = fee;
        return this.safeLedgerEntry(new java.util.HashMap<String, Object>() {{
            put( "info", item );
            put( "id", BitsoCore.this.safeString(item, "eid") );
            put( "direction", finalDirection );
            put( "account", null );
            put( "referenceId", finalReferenceId );
            put( "referenceAccount", null );
            put( "type", type );
            put( "currency", code );
            put( "amount", amount );
            put( "timestamp", timestamp );
            put( "datetime", BitsoCore.this.iso8601(timestamp) );
            put( "before", null );
            put( "after", null );
            put( "status", "ok" );
            put( "fee", finalFee );
        }}, currency);
    }

