    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        //     {
        //         "high":"37446.85",
        //         "last":"36599.54",
        //         "created_at":"2022-01-28T12:06:11+00:00",
        //         "book":"btc_usdt",
        //         "volume":"7.29075419",
        //         "vwap":"36579.1564400307",
        //         "low":"35578.52",
        //         "ask":"36574.76",
        //         "bid":"36538.22",
        //         "change_24":"-105.64"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object symbol = this.safeSymbol(null, market);
        Object timestamp = this.parse8601(this.safeString(ticker, "created_at"));
        Object vwap = this.safeString(ticker, "vwap");
        Object baseVolume = this.safeString(ticker, "volume");
        Object quoteVolume = Precise.stringMul(baseVolume, vwap);
        Object last = this.safeString(ticker, "last");
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", timestamp );
            put( "datetime", BitsoCore.this.iso8601(timestamp) );
            put( "high", BitsoCore.this.safeString(ticker, "high") );
            put( "low", BitsoCore.this.safeString(ticker, "low") );
            put( "bid", BitsoCore.this.safeString(ticker, "bid") );
            put( "bidVolume", null );
            put( "ask", BitsoCore.this.safeString(ticker, "ask") );
            put( "askVolume", null );
            put( "vwap", vwap );
            put( "open", null );
            put( "close", last );
            put( "last", last );
            put( "previousClose", null );
            put( "change", null );
            put( "percentage", null );
            put( "average", null );
            put( "baseVolume", baseVolume );
            put( "quoteVolume", quoteVolume );
            put( "info", ticker );
        }}, market);
    }

