    /**
     * @method
     * @name bitso#fetchOHLCV
     * @description fetches historical candlestick data containing the open, high, low, and close price, and the volume of a market
     * @param {string} symbol unified symbol of the market to fetch OHLCV data for
     * @param {string} timeframe the length of time each candle represents
     * @param {int} [since] timestamp in ms of the earliest candle to fetch
     * @param {int} [limit] the maximum amount of candles to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {int[][]} A list of candles ordered as timestamp, open, high, low, close, volume
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOHLCV(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object timeframe = Helpers.getArg(optionalArgs, 0, "1m");
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "book", Helpers.GetValue(market, "id") );
                put( "time_bucket", BitsoCore.this.safeString(BitsoCore.this.timeframes, timeframe, timeframe) );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "start", since);
                if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
                {
                    Object duration = this.parseTimeframe(timeframe);
                    Helpers.addElementToObject(request, "end", this.sum(since, Helpers.multiply(Helpers.multiply(duration, limit), 1000)));
                }
            } else if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Object now = this.milliseconds();
                Helpers.addElementToObject(request, "end", now);
                Helpers.addElementToObject(request, "start", Helpers.subtract(now, Helpers.multiply(Helpers.multiply(this.parseTimeframe(timeframe), 1000), limit)));
            }
            Object response = (this.publicGetOhlc(this.extend(request, parameters))).join();
            //
            //     {
            //         "success":true,
            //         "payload": [
            //             {
            //                 "bucket_start_time":1648219140000,
            //                 "first_trade_time":1648219154990,
            //                 "last_trade_time":1648219189442,
            //                 "first_rate":"44958.60",
            //                 "last_rate":"44979.88",
            //                 "min_rate":"44957.33",
            //                 "max_rate":"44979.88",
            //                 "trade_count":8,
            //                 "volume":"0.00082814",
            //                 "vwap":"44965.02"
            //             },
            //         ]
            //     }
            //
            Object payload = this.safeList(response, "payload", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseOHLCVs(payload, market, timeframe, since, limit);
        });

    }

    public Object parseOHLCV(Object ohlcv, Object... optionalArgs)
    {
        //
        //     {
        //         "bucket_start_time":1648219140000,
        //         "first_trade_time":1648219154990,
        //         "last_trade_time":1648219189441,
        //         "first_rate":"44958.60",
        //         "last_rate":"44979.88",
        //         "min_rate":"44957.33",
        //         "max_rate":"44979.88",
        //         "trade_count":8,
        //         "volume":"0.00082814",
        //         "vwap":"44965.02"
        //     },
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        return new java.util.ArrayList<Object>(java.util.Arrays.asList(this.safeInteger(ohlcv, "bucket_start_time"), this.safeNumber(ohlcv, "first_rate"), this.safeNumber(ohlcv, "max_rate"), this.safeNumber(ohlcv, "min_rate"), this.safeNumber(ohlcv, "last_rate"), this.safeNumber(ohlcv, "volume")));
    }

    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchTrades (public)
        //
        //      {
        //          "book": "btc_usdt",
        //          "created_at": "2021-11-24T12:14:53+0000",
        //          "amount": "0.00026562",
        //          "maker_side": "sell",
        //          "price": "56471.55",
        //          "tid": "52557338"
        //      }
        //
        // fetchMyTrades (private)
        //
        //      {
        //          "book": "btc_usdt",
        //          "created_at": "2021-11-24T12:31:03+0000",
        //          "minor": "11.30356000",
        //          "major": "-0.00020000",
        //          "fees_amount": "0.01119052",
        //          "fees_currency": "usdt",
        //          "minor_currency": "usdt",
        //          "major_currency": "btc",
        //          "oid": "djTzMIWx2Vi3iMjl",
        //          "tid": "52559051",
        //          "price": "56517.80",
        //          "side": "sell",
        //          "maker_side": "buy"
        //      }
        //
        // fetchOrderTrades (private)
        //
        //      {
        //          "book": "btc_usdt",
        //          "created_at": "2021-11-24T12:30:52+0000",
        //          "minor": "-11.33047916",
        //          "major": "0.00020020",
        //          "fees_amount": "0.00000020",
        //          "fees_currency": "btc",
        //          "minor_currency": "usdt",
        //          "major_currency": "btc",
        //          "oid": "O0D2zcljjjQF5xlG",
        //          "tid": "52559030",
        //          "price": "56595.80",
        //          "side": "buy",
        //          "maker_side": "sell"
        //      }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.parse8601(this.safeString(trade, "created_at"));
        Object marketId = this.safeString(trade, "book");
        Object symbol = this.safeSymbol(marketId, market, "_");
        Object side = this.safeString(trade, "side");
        Object makerSide = this.safeString(trade, "maker_side");
        Object takerOrMaker = null;
        if (Helpers.isTrue(!Helpers.isEqual(side, null)))
        {
            if (Helpers.isTrue(Helpers.isEqual(side, makerSide)))
            {
                takerOrMaker = "maker";
            } else
            {
                takerOrMaker = "taker";
            }
        } else
        {
            if (Helpers.isTrue(Helpers.isEqual(makerSide, "buy")))
            {
                side = "sell";
            } else
            {
                side = "buy";
            }
        }
        Object amount = this.safeString2(trade, "amount", "major");
        if (Helpers.isTrue(!Helpers.isEqual(amount, null)))
        {
            amount = Precise.stringAbs(amount);
        }
        Object fee = null;
        Object feeCost = this.safeString(trade, "fees_amount");
        if (Helpers.isTrue(!Helpers.isEqual(feeCost, null)))
        {
            Object feeCurrencyId = this.safeString(trade, "fees_currency");
            Object feeCurrency = this.safeCurrencyCode(feeCurrencyId);
            final Object finalFeeCost = feeCost;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCost );
                put( "currency", feeCurrency );
            }};
        }
        Object cost = this.safeString(trade, "minor");
        if (Helpers.isTrue(!Helpers.isEqual(cost, null)))
        {
            cost = Precise.stringAbs(cost);
        }
        Object price = this.safeString(trade, "price");
        Object orderId = this.safeString(trade, "oid");
        Object id = this.safeString(trade, "tid");
        final Object finalSide = side;
        final Object finalTakerOrMaker = takerOrMaker;
        final Object finalAmount = amount;
        final Object finalCost = cost;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "info", trade );
            put( "timestamp", timestamp );
            put( "datetime", BitsoCore.this.iso8601(timestamp) );
            put( "symbol", symbol );
            put( "order", orderId );
            put( "type", null );
            put( "side", finalSide );
            put( "takerOrMaker", finalTakerOrMaker );
            put( "price", price );
            put( "amount", finalAmount );
            put( "cost", finalCost );
            put( "fee", finalFee );
        }}, market);
    }

