    /**
     * @method
     * @name bitso#fetchMyTrades
     * @description fetch all trades made by the user
     * @see https://docs.bitso.com/bitso-api/docs/user-trades
     * @param {string} symbol unified market symbol
     * @param {int} [since] the earliest time in ms to fetch trades for
     * @param {int} [limit] the maximum number of trades structures to retrieve
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {Trade[]} a list of [trade structures]{@link https://docs.ccxt.com/?id=trade-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMyTrades(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, 25);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            // the don't support fetching trades starting from a date yet
            // use the `marker` extra param for that
            // this is not a typo, the variable name is 'marker' (don't confuse with 'market')
            Object markerInParams = (Helpers.inOp(parameters, "marker"));
            // warn the user with an exception if the user wants to filter
            // starting from since timestamp, but does not set the trade id with an extra 'marker' param
            if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(since, null))) && !Helpers.isTrue(markerInParams)))
            {
                throw new ExchangeError((String)Helpers.add(this.id, " fetchMyTrades() does not support fetching trades starting from a timestamp with the `since` argument, use the `marker` extra param to filter starting from an integer trade id")) ;
            }
            // convert it to an integer unconditionally
            if (Helpers.isTrue(markerInParams))
            {
                Object marker = Helpers.parseInt(Helpers.GetValue(parameters, "marker"));
                parameters = this.extend(parameters, new java.util.HashMap<String, Object>() {{
                    put( "marker", marker );
                }});
            }
            Object request = new java.util.HashMap<String, Object>() {{
                put( "book", Helpers.GetValue(market, "id") );
                put( "limit", limit );
            }};
            Object response = (this.privateGetUserTrades(this.extend(request, parameters))).join();
            return this.parseTrades(Helpers.GetValue(response, "payload"), market, since, limit);
        });

    }

