    public Object parseDepositWithdrawFees(Object response, Object... optionalArgs)
    {
        //
        //    {
        //        "fees": [
        //            {
        //                "book": "btc_mxn",
        //                "fee_percent": "0.6500",
        //                "fee_decimal": "0.00650000",
        //                "taker_fee_percent": "0.6500",
        //                "taker_fee_decimal": "0.00650000",
        //                "maker_fee_percent": "0.5000",
        //                "maker_fee_decimal": "0.00500000",
        //                "volume_currency": "mxn",
        //                "current_volume": "0.00",
        //                "next_volume": "1500000.00",
        //                "next_maker_fee_percent": "0.490",
        //                "next_taker_fee_percent": "0.637",
        //                "nextVolume": "1500000.00",
        //                "nextFee": "0.490",
        //                "nextTakerFee": "0.637"
        //            },
        //            ...
        //        ],
        //        "deposit_fees": [
        //            {
        //                "currency": "btc",
        //                "method": "rewards",
        //                "fee": "0.00",
        //                "is_fixed": false
        //            },
        //            ...
        //        ],
        //        "withdrawal_fees": {
        //            "ada": "0.20958100",
        //            "bch": "0.00009437",
        //            "ars": "0",
        //            "btc": "0.00001209",
        //            ...
        //        }
        //    }
        //
        Object codes = Helpers.getArg(optionalArgs, 0, null);
        Object currencyIdKey = Helpers.getArg(optionalArgs, 1, null);
        Object result = new java.util.HashMap<String, Object>() {{}};
        Object depositResponse = this.safeValue(response, "deposit_fees", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object withdrawalResponse = this.safeValue(response, "withdrawal_fees", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(depositResponse)); i++)
        {
            Object entry = Helpers.GetValue(depositResponse, i);
            Object currencyId = this.safeString(entry, "currency");
            Object code = this.safeCurrencyCode(currencyId);
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(codes, null))) || Helpers.isTrue((Helpers.inOp(codes, code)))))
            {
                Helpers.addElementToObject(result, code, new java.util.HashMap<String, Object>() {{
    put( "deposit", new java.util.HashMap<String, Object>() {{
        put( "fee", BitsoCore.this.safeNumber(entry, "fee") );
        put( "percentage", !Helpers.isTrue(BitsoCore.this.safeValue(entry, "is_fixed")) );
    }} );
    put( "withdraw", new java.util.HashMap<String, Object>() {{
        put( "fee", null );
        put( "percentage", null );
    }} );
    put( "networks", new java.util.HashMap<String, Object>() {{}} );
    put( "info", entry );
}});
            }
        }
        Object withdrawalKeys = Helpers.objectKeys(withdrawalResponse);
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(withdrawalKeys)); i++)
        {
            Object currencyId = Helpers.GetValue(withdrawalKeys, i);
            Object code = this.safeCurrencyCode(currencyId);
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(codes, null))) || Helpers.isTrue((Helpers.inOp(codes, code)))))
            {
                Object withdrawFee = this.parseNumber(Helpers.GetValue(withdrawalResponse, currencyId));
                Object resultValue = this.safeValue(result, code);
                if (Helpers.isTrue(Helpers.isEqual(resultValue, null)))
                {
                    Helpers.addElementToObject(result, code, this.depositWithdrawFee(new java.util.HashMap<String, Object>() {{}}));
                }
                Helpers.addElementToObject(Helpers.GetValue(Helpers.GetValue(result, code), "withdraw"), "fee", withdrawFee);
                Helpers.addElementToObject(Helpers.GetValue(Helpers.GetValue(result, code), "info"), code, withdrawFee);
            }
        }
        return result;
    }

    /**
     * @method
     * @name bitso#withdraw
     * @description make a withdrawal
     * @param {string} code unified currency code
     * @param {float} amount the amount to withdraw
     * @param {string} address the address to withdraw to
     * @param {string} tag
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [transaction structure]{@link https://docs.ccxt.com/?id=transaction-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> withdraw(Object code2, Object amount, Object address, Object... optionalArgs)
    {
        final Object code3 = code2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object code = code3;
            Object tag = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            var tagparametersVariable = this.handleWithdrawTagAndParams(tag, parameters);
            tag = ((java.util.List<Object>) tagparametersVariable).get(0);
            parameters = ((java.util.List<Object>) tagparametersVariable).get(1);
            this.checkAddress(address);
            (this.loadMarkets()).join();
            Object methods = new java.util.HashMap<String, Object>() {{
                put( "BTC", "Bitcoin" );
                put( "ETH", "Ether" );
                put( "XRP", "Ripple" );
                put( "BCH", "Bcash" );
                put( "LTC", "Litecoin" );
            }};
            Object currency = this.currency(code);
            Object method = ((Helpers.isTrue((Helpers.inOp(methods, code))))) ? Helpers.GetValue(methods, code) : null;
            if (Helpers.isTrue(Helpers.isEqual(method, null)))
            {
                throw new ExchangeError((String)Helpers.add(Helpers.add(this.id, " not valid withdraw coin: "), code)) ;
            }
            final Object finalTag = tag;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "amount", amount );
                put( "address", address );
                put( "destination_tag", finalTag );
            }};
            Object classMethod = Helpers.add(Helpers.add("privatePost", method), "Withdrawal");
            Object response = ((java.util.concurrent.CompletableFuture<Object>)Helpers.callDynamically(this, classMethod, new Object[] { this.extend(request, parameters) })).join();
            //
            //     {
            //         "success": true,
            //         "payload": [
            //             {
            //                 "wid": "c5b8d7f0768ee91d3b33bee648318688",
            //                 "status": "pending",
            //                 "created_at": "2016-04-08T17:52:31.000+00:00",
            //                 "currency": "btc",
            //                 "method": "Bitcoin",
            //                 "amount": "0.48650929",
            //                 "details": {
            //                     "withdrawal_address": "18MsnATiNiKLqUHDTRKjurwMg7inCrdNEp",
            //                     "tx_hash": "d4f28394693e9fb5fffcaf730c11f32d1922e5837f76ca82189d3bfe30ded433"
            //                 }
            //             },
            //         ]
            //     }
            //
            Object payload = this.safeValue(response, "payload", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object first = this.safeDict(payload, 0);
            return this.parseTransaction(first, currency);
        });

    }

    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        // deposit
        //     {
        //         "fid": "6112c6369100d6ecceb7f54f17cf0511",
        //         "status": "complete",
        //         "created_at": "2022-06-08T12:02:49+0000",
        //         "currency": "btc",
        //         "method": "btc",
        //         "method_name": "Bitcoin",
        //         "amount": "0.00080000",
        //         "asset": "btc",
        //         "network": "btc",
        //         "protocol": "btc",
        //         "integration": "bitgo-v2",
        //         "details": {
        //             "receiving_address": "3NmvbcYKhogs6RoTb4eYCUJ3beRSqLgSif",
        //             "tx_hash": "327f3838531f611485ec59f9d0a119fea1595591e274d942b2c10b9b8262eb1d",
        //             "confirmations": "4"
        //         }
        //     }
        //
        // withdraw
        //
        //     {
        //         "wid": "c5b8d7f0768ee91d3b33bee648318688",
        //         "status": "pending",
        //         "created_at": "2016-04-08T17:52:31.000+00:00",
        //         "currency": "btc",
        //         "method": "Bitcoin",
        //         "amount": "0.48650929",
        //         "details": {
        //             "withdrawal_address": "18MsnATiNiKLqUHDTRKjurwMg7inCrdNEp",
        //             "tx_hash": "d4f28394693e9fb5fffcaf730c11f32d1922e5837f76ca82189d3bfe30ded433"
        //         }
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object currencyId = this.safeString2(transaction, "currency", "asset");
        currency = this.safeCurrency(currencyId, currency);
        Object details = this.safeValue(transaction, "details", new java.util.HashMap<String, Object>() {{}});
        Object datetime = this.safeString(transaction, "created_at");
        Object withdrawalAddress = this.safeString(details, "withdrawal_address");
        Object receivingAddress = this.safeString(details, "receiving_address");
        Object networkId = this.safeString2(transaction, "network", "method");
        Object status = this.safeString(transaction, "status");
        Object withdrawId = this.safeString(transaction, "wid");
        Object networkCode = this.networkIdToCode(networkId, Helpers.GetValue(currency, "code"));
        Object networkCodeUpper = ((Helpers.isTrue((!Helpers.isEqual(networkCode, null))))) ? ((String)networkCode).toUpperCase() : null;
        final Object finalWithdrawalAddress = withdrawalAddress;
        final Object finalWithdrawId = withdrawId;
        final Object finalCurrency = currency;
        return new java.util.HashMap<String, Object>() {{
            put( "id", BitsoCore.this.safeString2(transaction, "wid", "fid") );
            put( "txid", BitsoCore.this.safeString(details, "tx_hash") );
            put( "timestamp", BitsoCore.this.parse8601(datetime) );
            put( "datetime", datetime );
            put( "network", networkCodeUpper );
            put( "addressFrom", receivingAddress );
            put( "address", ((Helpers.isTrue((!Helpers.isEqual(finalWithdrawalAddress, null))))) ? finalWithdrawalAddress : receivingAddress );
            put( "addressTo", finalWithdrawalAddress );
            put( "amount", BitsoCore.this.safeNumber(transaction, "amount") );
            put( "type", ((Helpers.isTrue((Helpers.isEqual(finalWithdrawId, null))))) ? "deposit" : "withdrawal" );
            put( "currency", BitsoCore.this.safeCurrencyCode(currencyId, finalCurrency) );
            put( "status", BitsoCore.this.parseTransactionStatus(status) );
            put( "updated", null );
            put( "tagFrom", null );
            put( "tag", null );
            put( "tagTo", null );
            put( "comment", null );
            put( "internal", null );
            put( "fee", null );
            put( "info", transaction );
        }};
    }

    public Object parseTransactionStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "pending", "pending" );
            put( "in_progress", "pending" );
            put( "complete", "ok" );
            put( "failed", "failed" );
        }};
        return this.safeString(statuses, status, status);
    }

    public Object nonce()
    {
        return this.milliseconds();
    }

    public Object sign(Object path, Object... optionalArgs)
    {
        Object api = Helpers.getArg(optionalArgs, 0, "public");
        Object method = Helpers.getArg(optionalArgs, 1, "GET");
        Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
        Object headers = Helpers.getArg(optionalArgs, 3, null);
        Object body = Helpers.getArg(optionalArgs, 4, null);
        Object endpoint = Helpers.add(Helpers.add(Helpers.add("/", this.version), "/"), this.implodeParams(path, parameters));
        Object query = this.omit(parameters, this.extractParams(path));
        if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(method, "GET")) || Helpers.isTrue(Helpers.isEqual(method, "DELETE"))))
        {
            if (Helpers.isTrue(Helpers.getArrayLength(Helpers.objectKeys(query))))
            {
                endpoint = Helpers.add(endpoint, Helpers.add("?", this.urlencode(query)));
            }
        }
        Object url = Helpers.add(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), "rest"), endpoint);
        if (Helpers.isTrue(Helpers.isEqual(api, "private")))
        {
            this.checkRequiredCredentials();
            Object nonce = String.valueOf(this.nonce());
            endpoint = Helpers.add("/api", endpoint);
            Object content = new java.util.ArrayList<Object>(java.util.Arrays.asList(nonce, method, endpoint));
            Object request = String.join((String)"", (java.util.List<String>)content);
            if (Helpers.isTrue(Helpers.isTrue(!Helpers.isEqual(method, "GET")) && Helpers.isTrue(!Helpers.isEqual(method, "DELETE"))))
            {
                if (Helpers.isTrue(Helpers.getArrayLength(Helpers.objectKeys(query))))
                {
                    body = this.json(query);
                    request = Helpers.add(request, body);
                }
            }
            Object signature = this.hmac(this.encode(request), this.encode(this.secret), sha256());
            Object auth = Helpers.add(Helpers.add(Helpers.add(Helpers.add(this.apiKey, ":"), nonce), ":"), signature);
            headers = new java.util.HashMap<String, Object>() {{
                put( "Authorization", Helpers.add("Bitso ", auth) );
            }};
        }
        final Object finalMethod = method;
        final Object finalBody = body;
        final Object finalHeaders = headers;
        return new java.util.HashMap<String, Object>() {{
            put( "url", url );
            put( "method", finalMethod );
            put( "body", finalBody );
            put( "headers", finalHeaders );
        }};
    }

    public Object handleErrors(Object httpCode, Object reason, Object url, Object method, Object headers, Object body, Object response, Object requestHeaders, Object requestBody)
    {
        if (Helpers.isTrue(Helpers.isEqual(response, null)))
        {
            return null;  // fallback to default error handler
        }
        if (Helpers.isTrue(Helpers.inOp(response, "success")))
        {
            //
            //     {"success":false,"error":{"code":104,"message":"Cannot perform request - nonce must be higher than 1520307203724237"}}
            //
            Object success = this.safeBool(response, "success", false);
            if (Helpers.isTrue((success instanceof String)))
            {
                if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(success, "true"))) || Helpers.isTrue((Helpers.isEqual(success, "1")))))
                {
                    success = true;
                } else
                {
                    success = false;
                }
            }
            if (!Helpers.isTrue(success))
            {
                Object feedback = Helpers.add(Helpers.add(this.id, " "), this.json(response));
                Object error = this.safeValue(response, "error");
                if (Helpers.isTrue(Helpers.isEqual(error, null)))
                {
                    throw new ExchangeError((String)feedback) ;
                }
                Object code = this.safeString(error, "code");
                this.throwExactlyMatchedException(this.exceptions, code, feedback);
                throw new ExchangeError((String)feedback) ;
            }
        }
        return null;
    }
